  1138→
  1139→### `fFA` — DirectConnectWebSocket (Browser Client)
  1140→
  1141→This is the simplest client implementation — useful as a reference for building your own:
  1142→
  1143→```typescript
  1144→class DirectConnectWebSocket {
  1145→  ws: WebSocket | null;
  1146→  config: { wsUrl: string; authToken?: string };
  1147→  callbacks: {
  1148→    onMessage: (msg: any) => void;
  1149→    onConnected?: () => void;
  1150→    onDisconnected?: () => void;
  1151→    onError?: (err: Error) => void;
  1152→    onPermissionRequest: (request: CanUseToolRequest, requestId: string) => void;
  1153→  };
  1154→
  1155→  connect(): void;
  1156→  sendMessage(content: string): boolean;
  1157→  respondToPermissionRequest(requestId: string, response: PermissionResponse): void;
  1158→  sendInterrupt(): void;
  1159→  disconnect(): void;
  1160→  isConnected(): boolean;
  1161→}
  1162→```
  1163→
  1164→**Key implementation details from `fFA`:**
  1165→```javascript
  1166→// Sending a user message
  1167→sendMessage(content) {
  1168→  const msg = JSON.stringify({
  1169→    type: "user",
  1170→    message: { role: "user", content },
  1171→    parent_tool_use_id: null,
  1172→    session_id: ""
  1173→  });
  1174→  this.ws.send(msg);
  1175→}
  1176→
  1177→// Responding to a permission request
  1178→respondToPermissionRequest(requestId, response) {
  1179→  const msg = JSON.stringify({
  1180→    type: "control_response",
  1181→    response: {
  1182→      subtype: "success",
  1183→      request_id: requestId,
  1184→      response: { behavior: response.behavior, ...response }
  1185→    }
  1186→  });
  1187→  this.ws.send(msg);
  1188→}
  1189→
  1190→// Sending an interrupt
  1191→sendInterrupt() {
  1192→  const msg = JSON.stringify({
  1193→    type: "control_request",
  1194→    request_id: crypto.randomUUID(),
  1195→    request: { subtype: "interrupt" }
  1196→  });
