# E2E Test Runner Script
# Runs comprehensive test suite for WebSocket Server
# Author: QA Tester Agent
# Date: 2026-02-10

param(
    [switch]$SkipServerStart = $false,
    [switch]$KeepServerRunning = $false,
    [string]$ReportPath = "tests/test-results.html"
)

# Configuration
$ErrorActionPreference = "Stop"
$ProjectRoot = Split-Path -Parent (Split-Path -Parent $PSScriptRoot)
$ServerLogFile = "$ProjectRoot/logs/server.log"
$TestLogFile = "$ProjectRoot/logs/test-results.log"
$ResultsDir = "$ProjectRoot/tests/results"

# Colors for output
function Write-ColorOutput {
    param(
        [string]$Message,
        [string]$Color = "White"
    )
    Write-Host $Message -ForegroundColor $Color
}

# Create results directory
New-Item -ItemType Directory -Force -Path $ResultsDir | Out-Null

# =============================================================================
# Start WebSocket Server
# =============================================================================

function Start-WebSocketServer {
    Write-ColorOutput "`n[START] Starting WebSocket Server..." "Cyan"

    # Check if already running
    $existingProcess = Get-Process -Name "node" -ErrorAction SilentlyContinue | Where-Object {
        $_.CommandLine -like "*8765*" -or $_.CommandLine -like "*index.ts*"
    }

    if ($existingProcess) {
        Write-ColorOutput "[WARN] Server already running (PID: $($existingProcess.Id))" "Yellow"
        return $existingProcess.Id
    }

    # Start server in background
    $serverLog = "$ProjectRoot/logs/server-test.log"
    $serverProcess = Start-Process -FilePath "bun" -ArgumentList "run server/index.ts" -WorkingDirectory $ProjectRoot -RedirectStandardOutput "$serverLog" -RedirectStandardError "$serverLog" -PassThru -WindowStyle Hidden

    # Wait for server to be ready
    Write-ColorOutput "[INFO] Waiting for server to start..." "Gray"
    $maxWait = 15
    $waited = 0
    $ready = $false

    while ($waited -lt $maxWait) {
        Start-Sleep -Seconds 1
        $waited++

        try {
            $response = Invoke-WebRequest -Uri "http://localhost:3001/health" -UseBasicParsing -TimeoutSec 2 -ErrorAction SilentlyContinue
            if ($response.StatusCode -eq 200) {
                $ready = $true
                break
            }
        } catch {
            # Server not ready yet
        }
    }

    if ($ready) {
        Write-ColorOutput "[SUCCESS] Server started (PID: $($serverProcess.Id))" "Green"
        return $serverProcess.Id
    } else {
        Write-ColorOutput "[ERROR] Server failed to start within ${maxWait}s" "Red"
        Write-ColorOutput "[INFO] Check log: $serverLog" "Gray"

        # Show log content
        if (Test-Path $serverLog) {
            Write-ColorOutput "`n--- Last 50 lines of server log ---" "Gray"
            Get-Content $serverLog -Tail 50 | Write-Host
        }

        Stop-Process -Id $serverProcess.Id -Force -ErrorAction SilentlyContinue
        exit 1
    }
}

# =============================================================================
# Stop WebSocket Server
# =============================================================================

function Stop-WebSocketServer {
    param([int]$ProcessId)

    if (-not $KeepServerRunning) {
        Write-ColorOutput "`n[STOP] Stopping WebSocket Server..." "Cyan"
        Stop-Process -Id $ProcessId -Force -ErrorAction SilentlyContinue
        Write-ColorOutput "[SUCCESS] Server stopped" "Green"
    } else {
        Write-ColorOutput "`n[INFO] Leaving server running (PID: $ProcessId)" "Yellow"
    }
}

# =============================================================================
# Install Dependencies
# =============================================================================

function Install-Dependencies {
    Write-ColorOutput "`n[CHECK] Checking test dependencies..." "Cyan"

    # Check Python
    $pythonVersion = python --version 2>&1
    if ($LASTEXITCODE -ne 0) {
        Write-ColorOutput "[ERROR] Python not found. Please install Python 3.8+" "Red"
        exit 1
    }
    Write-ColorOutput "[INFO] Python version: $pythonVersion" "Gray"

    # Install pip packages
    Write-ColorOutput "[INSTALL] Installing Python test dependencies..." "Cyan"
    & python -m pip install --quiet --upgrade pip
    & python -m pip install --quiet pytest pytest-asyncio websockets requests

    if ($LASTEXITCODE -eq 0) {
        Write-ColorOutput "[SUCCESS] Dependencies installed" "Green"
    } else {
        Write-ColorOutput "[ERROR] Failed to install dependencies" "Red"
        exit 1
    }
}

# =============================================================================
# Run Tests
# =============================================================================

function Run-Tests {
    Write-ColorOutput "`n[TEST] Running E2E Test Suite..." "Cyan"
    Write-ColorOutput "========================================`n" "Cyan"

    # Run pytest with output capture
    $testOutputFile = "$ResultsDir/pytest-output.txt"
    $testResultFile = "$ResultsDir/pytest-results.json"

    $env:PYTEST_CURRENT_TEST = ""

    & python -m pytest tests/test_e2e.py `
        -v `
        -m e2e `
        --tb=short `
        --color=yes `
        -W ignore `
        2>&1 | Tee-Object -FilePath $testOutputFile

    $exitCode = $LASTEXITCODE

    Write-ColorOutput "`n========================================" "Cyan"

    if ($exitCode -eq 0) {
        Write-ColorOutput "[SUCCESS] All tests PASSED!" "Green"
    } else {
        Write-ColorOutput "[FAILED] Some tests FAILED" "Red"
    }

    return $exitCode
}

# =============================================================================
# Generate HTML Report
# =============================================================================

function Generate-HTMLReport {
    param([int]$ExitCode)

    Write-ColorOutput "`n[REPORT] Generating HTML report..." "Cyan"

    $testOutput = Get-Content "$ResultsDir/pytest-output.txt" -Raw -ErrorAction SilentlyContinue
    $timestamp = Get-Date -Format "yyyy-MM-dd HH:mm:ss"

    # Parse test results
    $passed = 0
    $failed = 0
    $errors = 0
    $skipped = 0

    if ($testOutput) {
        $passed = ([regex]::Matches($testOutput, "PASSED")).Count
        $failed = ([regex]::Matches($testOutput, "FAILED")).Count
        $errors = ([regex]::Matches($testOutput, "ERROR")).Count
        $skipped = ([regex]::Matches($testOutput, "SKIPPED")).Count
    }

    $totalTests = $passed + $failed + $errors
    $passRate = if ($totalTests -gt 0) { [math]::Round(($passed / $totalTests) * 100, 1) } else { 0 }

